{"styles":{"css":"/**** Archea Contact Form ***/

.archea-contact-form .wpforms-field-container input[type="text"],
.archea-contact-form .wpforms-field-container input[type="number"],
.archea-contact-form .wpforms-field-textarea textarea,
.archea-contact-form .wpforms-field-container select ,
.archea-enquiry-form .wpforms-field-container input[type="text"],
.archea-enquiry-form .wpforms-field-container input[type="email"],
.archea-enquiry-form .wpforms-field-textarea textarea,
.archea-enquiry-form .wpforms-field-container select{
 border: 1px solid var(--wp--preset--color--grey-line) !important;
 font-size: 14px;
 font-weight: 400;
 font-family: inherit;
 line-height: 19.6px;
 border-radius: 12px;
 padding: 8px 12px;
 color: var(--wp--preset--color--black) !important;
 background-color: var(--wp--preset--color--white) !important;
}

.archea-contact-form .wpforms-field-textarea textarea,
.archea-enquiry-form .wpforms-field-textarea textarea {
 height: 131px !important;
 padding: 8px 12px !important;
}

.archea-contact-form .wpforms-field-container input[type="text"],
.archea-contact-form .wpforms-field-container input[type="number"],
.archea-contact-form .wpforms-field-container select,
.archea-enquiry-form .wpforms-field-container input[type="text"],
.archea-enquiry-form .wpforms-field-container input[type="number"],
.archea-enquiry-form .wpforms-field-container select{
 min-height: 50px !important;
}


.archea-contact-form .wpforms-field-container input[type="text"]:focus,
.archea-contact-form .wpforms-field-container textarea:focus,
.archea-contact-form .wpforms-field-container input[type="number"]:focus,
.archea-contact-form .wpforms-field-container select:focus,
.archea-enquiry-form .wpforms-field-container input[type="text"]:focus,
.archea-enquiry-form .wpforms-field-container textarea:focus,
.archea-enquiry-form .wpforms-field-container input[type="email"]:focus,
.archea-enquiry-form .wpforms-field-container select:focus{
 outline: 1px solid rgba(34, 34, 34, 0.4) !important;
 box-shadow: none !important;
}

.archea-contact-form .wpforms-field-container input[type="text"]::placeholder,
.archea-contact-form .wpforms-field-textarea textarea::placeholder,
.archea-contact-form .wpforms-field-container input[type="number"]::placeholder,
.archea-contact-form .wpforms-field-container select::placeholder,
.archea-enquiry-form .wpforms-field-container input[type="text"]::placeholder,
.archea-enquiry-form .wpforms-field-textarea textarea::placeholder,
.archea-enquiry-form .wpforms-field-container input[type="email"]::placeholder,
.archea-enquiry-form .wpforms-field-container select::placeholder, {
 color: var(--wp--preset--color--black) !important;
}

.archea-contact-form .wpforms-submit-container button[type="submit"],
.archea-enquiry-form .wpforms-submit-container button[type="submit"] {
 width: 100%;
 background-color: var(--wp--preset--color--black) !important;
 font-size: 18px;
 font-weight: 400;
 border-radius: 12px;
 text-align: center;
 color: var(--wp--preset--color--white) !important;
 height: 50px !important;
 box-shadow: none;
 border: transparent;
 cursor: pointer;
 margin-top:22px;
}

.archea-contact-form .wpforms-submit-container button[type="submit"]:focus::after,
.archea-enquiry-form .wpforms-submit-container button[type="submit"]:focus::after
{
 border: none !important;
}


.archea-contact-form .wpforms-field-container .wpforms-field-label,
.archea-enquiry-form .wpforms-field-container .wpforms-field-label {
 font-size: 18px;
 font-weight: 400;
 font-family: Inter;
 line-height: 25.2px;
 color: var(--wp--preset--color--black) !important;
 margin-bottom: 8px;
}

.archea-contact-form .wpforms-field,
.archea-enquiry-form .wpforms-field {
 padding: 0px !important; 
}

@media (min-width: 768px) {

 .archea-contact-form .wpforms-field-container {
 display: flex;
 flex-wrap: wrap;
 column-gap: 32px;
 row-gap: 24px !important;
 }

 .archea-contact-form.wpforms-container .wpforms-field {
 width: 47.5% !important;
 margin-bottom: 0;
 }

 .archea-contact-form .wpforms-field.wpforms-field-textarea {
 width: 100% !important;
 }
}

@media (min-width: 768px) {

 .archea-enquiry-form .wpforms-field-container {
 display: flex;
 flex-wrap: wrap;
 column-gap: 32px;
 row-gap: 24px !important;
 }

 .archea-enquiry-form.wpforms-container .wpforms-field {
 width: 46% !important;
 margin-bottom: 0;
 }

 .archea-enquiry-form .wpforms-field.wpforms-field-textarea,
 .archea-enquiry-form .wpforms-field.wpforms-field-select {
 width: 100% !important;
 }
}


@media (max-width: 767px) {

 .archea-contact-form .wpforms-field,
 .archea-enquiry-form .wpforms-field {
 width: 100% !important;
 margin-bottom: 12px;
 }
}

.archea-contact-form.wpforms-container-full:not(:empty) ,
.archea-enquiry-form.wpforms-container-full:not(:empty) {
 margin: 0px;
}

.archea-subscribe-form{
 margin: 0 !important;
}

.archea-subscribe-form .wpforms-form {
 position: relative !important;
}

.archea-subscribe-form .wpforms-field-container .wpforms-field{
 padding: 0px !important;
}

.archea-subscribe-form .wpforms-field-container input[type="email"] {
 min-height: 72px !important;
 padding: 0px 24px !important;
 border: 1px solid var(--wp--preset--color--grey-line) !important;
 font-size: 16px;
 font-weight: 400;
 color: var(--wp--preset--color--white) !important;
 background-color: transparent !important;
 border-radius: 12px !important;

}

.archea-subscribe-form .wpforms-field-container input[type="email"]:focus {
 border: none;
 box-shadow: none !important;
}

.archea-subscribe-form input[type="email"]::placeholder {
 color: var(--wp--preset--color--light-grey-text) !important;
 line-height: 22.4px;
 font-weight: 500 !important;
 font-size: 16px;
}

.archea-subscribe-form .wpforms-submit-container {
 margin-top: 20px !important;
 }


.archea-subscribe-form .wpforms-submit-container button[type="submit"] {
 align-items:center;
 justify-content: center;
 white-space: nowrap;
 padding: 11px 32px;
 font-weight: 500;
 font-size: 18px !important;
 color: var(--wp--preset--color--black) !important;
 line-height: 25.2px;
 background-color: var(--wp--preset--color--white) !important;
 border-radius: 12px !important;
 box-sizing: border-box;
 height: 72px !important;
 cursor:pointer;
 width: 158px !important;
}


.archea-subscribe-form .wpforms-field-container input[type="email"]:focus {
 box-shadow: none !important;
}


@media (min-width: 768px) {

 .archea-subscribe-form .wpforms-field-container input[type="email"] {
 width: 482px;
 }

 .archea-subscribe-form .wpforms-submit-container {
 text-align: center;
 position: absolute !important;
 right: 0px !important;
 top: 0px !important;
 margin-top: 0px !important;

 }

}"},"isGlobalStylesUserThemeJSON":true,"version":3}
